// audio-crackle.js — Web Audio crackle system + base64 OGG data

    // ─── 熔炉火焰音效系统（Web Audio，交叉淡入淡出）────────────────────
    const _CRACKLE_SRCS = [
  'data:audio/ogg;base64,',
  'data:audio/ogg;base64,',
  'data:audio/ogg;base64,',
  'data:audio/ogg;base64,',
  'data:audio/ogg;base64,'
    ];

    const _audioCtx   = new (window.AudioContext || window.webkitAudioContext)();
    const _masterGain = _audioCtx.createGain();
    _masterGain.connect(_audioCtx.destination);

    const _crackleBuffers = [];
    let   _lastCrackleIdx = -1;  // 记录上一次播放的索引，下次排除
    let   _crackleRunning = false;
    let   _crackleTimer   = null;

    // WE 用户可调基础音量（0~1），由 project.json cracklevol 参数控制，默认 1.0
    let _crackleMasterVol = 1.0;

    // 监听 Wallpaper Engine 用户属性变化（在此作用域内定义，可安全访问 _setCrackleVol）
    window.wallpaperPropertyListener = {
      applyUserProperties: function(props) {
        // autounmute：WE 加载时自动解除静音
        if (props.autounmute && props.autounmute.value === true) {
          if (typeof window._weAutoUnmuteOnReady === 'function') {
            window._weAutoUnmuteOnReady();
          }
        }
        if (props.cracklevol !== undefined) {
          _crackleMasterVol = props.cracklevol.value / 100;
          _setCrackleVol();
        }
      }
    };

    // 音量映射：fire>=50 全音量，<50 幂函数衰减，再乘以用户基础音量
    function _crackleVolume() {
      const fireVol = furnaceLevel >= 50 ? 1.0
                    : furnaceLevel <= 0  ? 0
                    : Math.pow(furnaceLevel / 50, 1.5);
      return fireVol * _crackleMasterVol;
    }

    // 用 XHR 加载单个 buffer（file:// 协议兼容，fetch 在本地文件会被 CORS 阻止）
    function _xhrBuffer(src) {
      return new Promise((resolve, reject) => {
        const xhr = new XMLHttpRequest();
        xhr.open('GET', src, true);
        xhr.responseType = 'arraybuffer';
        xhr.onload = () => _audioCtx.decodeAudioData(xhr.response, resolve, reject);
        xhr.onerror = reject;
        xhr.send();
      });
    }

    // 异步预加载所有音频 buffer
    async function _loadCrackleBuffers() {
      for (const src of _CRACKLE_SRCS) {
        try {
          _crackleBuffers.push(await _xhrBuffer(src));
        } catch(e) { /* 单文件失败不影响其他 */ }
      }
    }

    // 调度一段音频：per-clip GainNode 控制淡入淡出，结束前 0.2s 触发下一段
    function _scheduleClip(startAt) {
      if (!_crackleRunning || _crackleBuffers.length === 0) return;

      // 从除上次之外的索引中随机选一个
      const _indices = _crackleBuffers.map((_, i) => i).filter(i => i !== _lastCrackleIdx);
      const _pick    = _indices[Math.floor(Math.random() * _indices.length)];
      _lastCrackleIdx = _pick;
      const buf     = _crackleBuffers[_pick];
      const dur     = buf.duration;
      const fadeIn  = 0.10;  // 短淡入，几乎立刻满音量
      const fadeOut = 0.15;  // 短淡出，避免音量凹陷
      const overlap = 0.60;  // 两段音频重叠 0.6s，确保不断声

      const clipGain = _audioCtx.createGain();
      clipGain.connect(_masterGain);
      clipGain.gain.setValueAtTime(0,  startAt);
      clipGain.gain.linearRampToValueAtTime(1, startAt + fadeIn);
      clipGain.gain.setValueAtTime(1,  startAt + dur - fadeOut);
      clipGain.gain.linearRampToValueAtTime(0, startAt + dur);

      const src = _audioCtx.createBufferSource();
      src.buffer = buf;
      src.connect(clipGain);
      src.start(startAt);
      src.stop(startAt + dur);

      // 下一段在本段结束前 overlap 秒开始
      const nextAt  = startAt + dur - overlap;
      const msDelay = Math.max(0, (nextAt - _audioCtx.currentTime) * 1000);
      _crackleTimer = setTimeout(() => {
        _crackleTimer = null;
        _scheduleClip(_audioCtx.currentTime);
      }, msDelay);
    }

    _loadCrackleBuffers();  // 提前异步预加载，点击时即可直接播放

    function _startCrackle() {
      if (_crackleRunning || !userUnmuted) return;
      _audioCtx.resume().then(() => {
        _crackleRunning = true;
        _masterGain.gain.setValueAtTime(_crackleVolume() * _crackleDuck, _audioCtx.currentTime);
        if (_crackleBuffers.length > 0) {
          _scheduleClip(_audioCtx.currentTime);
        } else {
          _loadCrackleBuffers().then(() => {
            if (_crackleRunning) _scheduleClip(_audioCtx.currentTime);
          });
        }
      });
    }

    function _stopCrackle() {
      _crackleRunning = false;
      if (_crackleTimer) { clearTimeout(_crackleTimer); _crackleTimer = null; }
      _masterGain.gain.linearRampToValueAtTime(0, _audioCtx.currentTime + 0.4);
    }

    function _setCrackleVol() {
      const vol = _crackleVolume() * _crackleDuck;
      _masterGain.gain.cancelScheduledValues(_audioCtx.currentTime);
      _masterGain.gain.linearRampToValueAtTime(vol, _audioCtx.currentTime + 0.15);
      if (vol <= 0 && _crackleRunning) _stopCrackle();
      else if (vol > 0 && !_crackleRunning && userUnmuted) _startCrackle();
    }

    // 音乐播放时压低炉声，duck=1.0 正常，duck=0.1 压到10%
    var _crackleDuck = 1.0;
    window.setCrackleDuck = function(duck, durationSec) {
      _crackleDuck = duck;
      const t = _audioCtx.currentTime;
      const d = durationSec || 1.5;
      const target = _crackleVolume() * duck;
      _masterGain.gain.cancelScheduledValues(t);
      _masterGain.gain.linearRampToValueAtTime(target, t + d);
    };

